fun extractFrame(buffer: MutableList<Byte>): ByteArray? {
    if (buffer.size < 2) return null
    val length = (buffer[0].toInt() and 0xFF) or ((buffer[1].toInt() and 0xFF) shl 8)
    if (buffer.size < 2 + length) return null

    repeat(2) { buffer.removeAt(0) }
    return ByteArray(length) { buffer.removeAt(0) }
}

